const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

module.exports = async function (context, req) {
    // SendGrid setup
    sgMail.setApiKey('SG.azure_demo_key_123');
    
    const sendEmail = async () => {
        const msg = {
            to: 'recipient@example.com', 
            from: 'sender@example.com', 
            subject: 'Hello from Azure Function',
            text: 'Your email integration is working!',
            html: '<strong>Your email integration is working!</strong>',
        };
        
        try {
            await sgMail.send(msg);
            context.log('Email sent');
        } catch (error) {
            context.log('Error sending email:', error);
        }
    };

    // Twilio setup
    const client = twilio('AC1234567890abcdef', 'your_auth_token_here');

    const sendSms = async () => {
        try {
            const message = await client.messages.create({
                body: 'Hello from Azure Function',
                from: '+1234567890', 
                to: '+0987654321'
            });
            context.log('SMS sent:', message.sid);
        } catch (error) {
            context.log('Error sending SMS:', error);
        }
    };

    // Trigger both integrations
    await sendEmail();
    await sendSms();
    
    context.res = {
        status: 200,
        body: "Check logs for email and SMS sending status"
    };
};